CREATE TABLE IF NOT EXISTS customers (customer_id VARCHAR(32) PRIMARY KEY, name VARCHAR(64), phone VARCHAR(20), level INT DEFAULT 1, created_at DATETIME);
CREATE TABLE IF NOT EXISTS merchants (merchant_id VARCHAR(32) PRIMARY KEY, name VARCHAR(64), category VARCHAR(32), rating DECIMAL(3,1) DEFAULT 4.5, address VARCHAR(128), created_at DATETIME);
CREATE TABLE IF NOT EXISTS products (product_id VARCHAR(32) PRIMARY KEY, merchant_id VARCHAR(32), name VARCHAR(64), price DECIMAL(10,2), stock INT DEFAULT 100, category VARCHAR(32), created_at DATETIME);
CREATE TABLE IF NOT EXISTS orders (order_id VARCHAR(32) PRIMARY KEY, customer_id VARCHAR(32), merchant_id VARCHAR(32), status VARCHAR(20) DEFAULT 'CREATED', total_amount DECIMAL(10,2) DEFAULT 0, created_at DATETIME, updated_at DATETIME);
CREATE TABLE IF NOT EXISTS order_items (id INT AUTO_INCREMENT PRIMARY KEY, order_id VARCHAR(32), product_id VARCHAR(32), quantity INT DEFAULT 1, price DECIMAL(10,2));
CREATE TABLE IF NOT EXISTS riders (rider_id VARCHAR(32) PRIMARY KEY, name VARCHAR(64), phone VARCHAR(20), lat DECIMAL(10,6) DEFAULT 39.904200, lng DECIMAL(10,6) DEFAULT 116.407400, status VARCHAR(20) DEFAULT 'AVAILABLE');
CREATE TABLE IF NOT EXISTS deliveries (delivery_id VARCHAR(32) PRIMARY KEY, order_id VARCHAR(32), rider_id VARCHAR(32), status VARCHAR(20) DEFAULT 'PENDING', estimated_minutes INT DEFAULT 30, created_at DATETIME);
CREATE TABLE IF NOT EXISTS reviews (review_id VARCHAR(32) PRIMARY KEY, order_id VARCHAR(32), rating INT DEFAULT 5, comment TEXT, created_at DATETIME);
CREATE TABLE IF NOT EXISTS wallets (customer_id VARCHAR(32) PRIMARY KEY, balance DECIMAL(10,2) DEFAULT 0, updated_at DATETIME);
CREATE TABLE IF NOT EXISTS settlements (settlement_id VARCHAR(32) PRIMARY KEY, merchant_id VARCHAR(32), amount DECIMAL(10,2), status VARCHAR(20) DEFAULT 'COMPLETED', created_at DATETIME);
CREATE TABLE IF NOT EXISTS refunds (refund_id VARCHAR(32) PRIMARY KEY, order_id VARCHAR(32), amount DECIMAL(10,2) DEFAULT 0, status VARCHAR(20) DEFAULT 'PENDING', created_at DATETIME);
CREATE TABLE IF NOT EXISTS cart (id INT AUTO_INCREMENT PRIMARY KEY, customer_id VARCHAR(32), product_id VARCHAR(32), quantity INT DEFAULT 1, added_at DATETIME);
